1	type Cell = [number, number];
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const result: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      result.push([x + dx, y + dy]);
11	    }
12	  }
13	  return result;
14	};
15	
16	const isAliveNextGeneration = (isCurrentlyAlive: boolean, liveNeighborCount: number): boolean =>
17	  liveNeighborCount === 3 || (isCurrentlyAlive && liveNeighborCount === 2);
18	
19	export function nextGeneration(grid: Cell[]): Cell[] {
20	  const liveSet = new Set(grid.map(toKey));
21	  const candidates = new Map<string, Cell>();
22	
23	  for (const cell of grid) {
24	    candidates.set(toKey(cell), cell);
25	    for (const neighbor of neighborsOf(cell)) {
26	      candidates.set(toKey(neighbor), neighbor);
27	    }
28	  }
29	
30	  const result: Cell[] = [];
31	  for (const cell of candidates.values()) {
32	    const liveNeighborCount = neighborsOf(cell).filter((n) =>
33	      liveSet.has(toKey(n))
34	    ).length;
35	    if (isAliveNextGeneration(liveSet.has(toKey(cell)), liveNeighborCount)) {
36	      result.push(cell);
37	    }
38	  }
39	
40	  return result;
41	}
